CREATE TABLE public.crm_referral_company_signups (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE, partner_id UUID NOT NULL REFERENCES public.crm_referral_partners(id) ON DELETE CASCADE, link_id UUID REFERENCES public.crm_referral_links(id) ON DELETE SET NULL, company_id UUID REFERENCES public.tenants(id) ON DELETE SET NULL, signup_status public.crm_signup_status NOT NULL DEFAULT 'pending', company_name TEXT NOT NULL, company_email TEXT NOT NULL, company_phone TEXT, admin_user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL, first_invoice_amount NUMERIC(10,2), first_year_value NUMERIC(10,2), subscription_plan TEXT, paid_at TIMESTAMPTZ, churned_at TIMESTAMPTZ, payout_eligible BOOLEAN NOT NULL DEFAULT false, payout_eligible_at TIMESTAMPTZ, payout_id UUID, fraud_flag BOOLEAN NOT NULL DEFAULT false, notes TEXT, metadata JSONB DEFAULT '{}', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE TABLE public.crm_referral_payout_profiles (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE, partner_id UUID NOT NULL REFERENCES public.crm_referral_partners(id) ON DELETE CASCADE, payment_method TEXT NOT NULL, account_name TEXT, account_number_last4 TEXT, routing_number TEXT, bank_name TEXT, paypal_email TEXT, venmo_handle TEXT, is_verified BOOLEAN NOT NULL DEFAULT false, verification_method TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE(tenant_id, partner_id)); CREATE TABLE public.crm_referral_program_settings (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL UNIQUE REFERENCES public.tenants(id) ON DELETE CASCADE, program_enabled BOOLEAN NOT NULL DEFAULT false, auto_approve_partners BOOLEAN NOT NULL DEFAULT false, default_payout_type public.crm_payout_type NOT NULL DEFAULT 'fixed_fee', default_payout_value NUMERIC(10,2) NOT NULL DEFAULT 100, default_partner_tier public.crm_partner_tier NOT NULL DEFAULT 'standard', signup_bonus_enabled BOOLEAN NOT NULL DEFAULT true, signup_bonus_amount NUMERIC(10,2) DEFAULT 50, first_invoice_percentage NUMERIC(5,2) DEFAULT 10, first_year_percentage NUMERIC(5,2) DEFAULT 5, min_payout_threshold NUMERIC(10,2) DEFAULT 25, payout_schedule TEXT DEFAULT 'monthly', fraud_checks_enabled BOOLEAN NOT NULL DEFAULT true, duplicate_company_check BOOLEAN NOT NULL DEFAULT true, self_referral_block BOOLEAN NOT NULL DEFAULT true, max_velocity_per_hour INTEGER DEFAULT 100, email_notifications BOOLEAN NOT NULL DEFAULT true, custom_terms TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());